import anthropic
import json
from dataclasses import dataclass, field

@dataclass
class ResearchProtocol:
    question: str
    pico: dict
    design: str
    population: str
    sample_size: int
    primary_outcome: str
    statistical_tests: list[str] = field(default_factory=list)
    ethical_considerations: str = ""

class AcademicResearchPipeline:
    def __init__(self):
        self.client = anthropic.Anthropic()

    def formalise_question(self, free_text_question: str) -> dict:
        """Convert a research question to PICO format."""
        response = self.client.messages.create(
            model="claude-opus-4-5",
            max_tokens=512,
            messages=[{"role": "user", "content": f"""
Convert this research question to PICO format.
Return JSON: {{"P": "Population", "I": "Intervention", "C": "Comparison", "O": "Outcome", "formalised_question": "..."}}

Research question: {free_text_question}
"""}]
        )
        text = response.content[0].text
        return json.loads(text[text.find("{"):text.rfind("}")+1])

    def design_protocol(self, pico: dict, study_type: str) -> str:
        """Draft a research protocol."""
        response = self.client.messages.create(
            model="claude-opus-4-5",
            max_tokens=2048,
            messages=[{"role": "user", "content": f"""
Draft a research protocol for a {study_type} study.
PICO: {json.dumps(pico)}

Include sections: Background, Objectives, Methods (design, participants, intervention, outcomes),
Statistical analysis plan, Ethical considerations.
Be specific about inclusion/exclusion criteria and statistical tests.
"""}]
        )
        return response.content[0].text

    def recommend_statistics(self, design: str, outcome_type: str, sample_size: int, groups: int) -> dict:
        """Recommend statistical analysis approach."""
        response = self.client.messages.create(
            model="claude-opus-4-5",
            max_tokens=512,
            messages=[{"role": "user", "content": f"""
Recommend statistical analysis for this study.
Design: {design}
Primary outcome: {outcome_type} variable
Sample size: {sample_size}
Number of groups: {groups}

Return JSON: {{"primary_test": "...", "assumptions_to_check": [...], "effect_size_measure": "...", "corrections_needed": [...]}}
"""}]
        )
        text = response.content[0].text
        return json.loads(text[text.find("{"):text.rfind("}")+1])

    def draft_methods_section(self, protocol: ResearchProtocol) -> str:
        """Draft the Methods section of a manuscript."""
        response = self.client.messages.create(
            model="claude-opus-4-5",
            max_tokens=1500,
            messages=[{"role": "user", "content": f"""
Write the Methods section of a manuscript for this study.

Research question: {protocol.question}
Study design: {protocol.design}
Population: {protocol.population}
Sample size: {protocol.sample_size}
Primary outcome: {protocol.primary_outcome}
Statistical tests: {", ".join(protocol.statistical_tests)}
Ethical considerations: {protocol.ethical_considerations}

Follow CONSORT/STROBE reporting guidelines. Use past tense. Include subsections:
Participants, Measures, Procedure, Statistical Analysis.
"""}]
        )
        return response.content[0].text

    def check_reporting_compliance(self, manuscript_text: str, guideline: str = "CONSORT") -> list[str]:
        """Check manuscript compliance with reporting standards."""
        response = self.client.messages.create(
            model="claude-opus-4-5",
            max_tokens=768,
            messages=[{"role": "user", "content": f"""
Check this manuscript extract for {guideline} compliance.
Return a JSON list of missing or incomplete items:
[{{"item": "CONSORT item X", "issue": "missing/incomplete", "suggestion": "..."}}]

Manuscript (first 2000 chars):
{manuscript_text[:2000]}
"""}]
        )
        text = response.content[0].text
        start, end = text.find("["), text.rfind("]") + 1
        return json.loads(text[start:end]) if start >= 0 else []

    def draft_reviewer_response(self, reviewer_comments: str, manuscript_excerpt: str) -> str:
        """Draft a point-by-point reviewer response."""
        response = self.client.messages.create(
            model="claude-opus-4-5",
            max_tokens=2000,
            messages=[{"role": "user", "content": f"""
Draft a point-by-point response to these reviewer comments.
Format: "Reviewer Comment: [quote] | Response: [draft response] | Manuscript Change: [what was changed]"

Reviewer comments:
{reviewer_comments}

Relevant manuscript sections:
{manuscript_excerpt[:1500]}
"""}]
        )
        return response.content[0].text

# Usage
pipeline = AcademicResearchPipeline()

pico = pipeline.formalise_question(
    "Does mindfulness meditation reduce anxiety in university students?"
)
print("PICO:", json.dumps(pico, indent=2))

stats = pipeline.recommend_statistics(
    design="RCT", outcome_type="continuous", sample_size=80, groups=2
)
print("Statistics:", json.dumps(stats, indent=2))
